#!/usr/bin/env python3
import sys

def solve():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out_lines = []
    for _ in range(T):
        N = int(next(it))
        arr = [int(next(it)) for _ in range(N)]
        # pair value with original index
        sorted_pairs = sorted((val, idx) for idx, val in enumerate(arr))
        pos = [0] * N
        for new_idx, (_, old_idx) in enumerate(sorted_pairs):
            pos[old_idx] = new_idx
        visited = [False] * N
        swaps = 0
        for i in range(N):
            if not visited[i]:
                cur = i
                length = 0
                while not visited[cur]:
                    visited[cur] = True
                    cur = pos[cur]
                    length += 1
                if length > 0:
                    swaps += length - 1
        out_lines.append(str(swaps))
    sys.stdout.write('\n'.join(out_lines))

if __name__ == "__main__":
    solve()

