for (let t = 0; t < T; ++t) {
  const N = Number(input[idx++]);
  const arr = new Array(N);
  for (let i = 0; i < N; ++i) arr[i] = Number(input[idx++]);
  const pairs = arr.map((v, i) => ({val: v, idx: i}));
  pairs.sort((a, b) => a.val - b.val);
  const pos = new Array(N);
  for (let i = 0; i < N; ++i) pos[pairs[i].idx] = i;
  const visited = new Array(N).fill(false);
  let swaps = 0;
  for (let i = 0; i < N; ++i) {
    if (!visited[i]) {
      let cur = i;
      let len = 0;
      while (!visited[cur]) {
        visited[cur] = true;
        cur = pos[cur];
        ++len;
      }
      if (len > 0) swaps += len - 1;
    }
  }
  outputs.push(String(swaps));
}
